### 7. **IMAGE MODEL IMPLEMENTATION** (Core Logic)

The image model class implements `ImageModelV3` interface:

```typescript
import {
  ImageModelV3,
  ImageModelV3File,
  SharedV3Warning,
} from '@ai-sdk/provider';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return 4; // Or dynamic based on modelId
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: SharedV3Warning[] = [];

    // Handle unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    }

    // Build API request
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.baseURL + '/generate',
      headers: combineHeaders(this.config.headers, headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...providerOptions.pixelart,
      },
      successfulResponseHandler: createJsonResponseHandler(schema),
      failedResponseHandler: pixelartFailedResponseHandler,
      fetch: this.config.fetch,
    });

    // Return standardized response
    return {
      images: response.data.map(item => item.b64_json), // base64 or Uint8Array
      warnings,
      usage: {
        inputTokens: response.usage?.input_tokens,
        outputTokens: response.usage?.output_tokens,
        totalTokens: response.usage?.total_tokens,
      },
      response: {
        timestamp: new Date(),
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(item => ({
            // Provider-specific metadata
          })),
        },
      },
    };
  }
}
```

