          fs.readFileSync('src/__fixtures__/pixelart-image.json', 'utf8'),
        ),
      },
    },
  });

  describe('doGenerate', () => {
    it('sends correct URL, method, and body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
