### File 5: `packages/pixelart/src/pixelart-provider.ts`

The factory function and default singleton. Mirrors `black-forest-labs-provider.ts` and `luma-provider.ts` closely. Uses `withUserAgentSuffix` to append the SDK user-agent, `loadApiKey` to read from `PIXELART_API_KEY`, and `withoutTrailingSlash` to normalize the base URL.

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withUserAgentSuffix,
  withoutTrailingSlash,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Default value is taken from the `PIXELART_API_KEY`
   * environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API. Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Can be used as middleware to intercept
   * requests or to provide a test double.
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a model for image generation.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   * Alias for `image()` following the ProviderV3 convention.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
  };
}

export const pixelart = createPixelArt();
```

Note: `textEmbeddingModel` is NOT included here. Looking at the `ProviderV3` interface, `textEmbeddingModel` is a deprecated alias that only some providers carry. `luma-provider.ts` includes it, but `black-forest-labs-provider.ts` includes it as `never`. Since the requirements say it is image-only and do not mention deprecated aliases, and since new providers (e.g. `luma`) still keep it for backwards compat with older consumers, it is safer to include it. However, the requirements do not mandate it, so it can be added if stricter ProviderV3 conformance is needed. For now, following the minimal pattern.

