import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art dragon';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/generate': {
      response: {
        type: 'json-value',
        body: {
          images: ['dGVzdC1pbWFnZS1kYXRh'],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('passes prompt, n, size, and seed to the API', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
      });
    });

    it('passes style and pixelDensity provider options to the API', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 8,
          },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        style: 'retro',
        pixel_density: 8,
      });
    });

    it('passes 8bit style correctly', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: '8bit',
          },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: '8bit',
      });
    });

    it('omits style and pixelDensity when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('warns when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support aspectRatio. Use size instead.",
            "feature": "aspectRatio",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('warns when files are provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: [{ type: 'url', url: 'https://example.com/image.png', mediaType: 'image/png' }],
        mask: undefined,
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support input files.",
            "feature": "files",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('warns when mask is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: { type: 'url', url: 'https://example.com/mask.png', mediaType: 'image/png' },
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support image masks.",
            "feature": "mask",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('calls the expected URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/v1/generate',
      );
    });

    it('merges provider and request headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'X-Custom-Provider': 'provider-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'X-Custom-Request': 'request-value',
        },
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        authorization: 'Bearer test-key',
        'x-custom-provider': 'provider-value',
        'x-custom-request': 'request-value',
      });
    });

    it('returns images from the API response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe('dGVzdC1pbWFnZS1kYXRh');
    });

    it('returns multiple images when n > 1', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'json-value',
        body: {
          images: ['aW1hZ2Ux', 'aW1hZ2Uy', 'aW1hZ2Uz'],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 3,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(3);
      expect(result.images).toStrictEqual(['aW1hZ2Ux', 'aW1hZ2Uy', 'aW1hZ2Uz']);
    });

    it('handles API errors with error field', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: 'Invalid prompt',
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
      });
    });

    it('handles API errors with message field', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'error',
        status: 422,
        body: JSON.stringify({
          message: 'Unsupported style value',
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Unsupported style value',
        statusCode: 422,
      });
    });

    it('includes timestamp, headers, and modelId in response', async () => {
      const testDate = new Date('2025-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-v1',
        headers: expect.any(Object),
      });
    });

    it('returns empty warnings when no unsupported features are used', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toStrictEqual([]);
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information for pixelart-v1', () => {
      const model = new PixelArtImageModel('pixelart-v1', {
        provider: 'pixelart.image',
        baseURL: 'https://api.pixelart.ai/v1',
        headers: () => ({ Authorization: 'Bearer key' }),
      });

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });

    it('exposes correct maxImagesPerCall for pixelart-v2', () => {
      const model = new PixelArtImageModel('pixelart-v2', {
        provider: 'pixelart.image',
        baseURL: 'https://api.pixelart.ai/v1',
        headers: () => ({ Authorization: 'Bearer key' }),
      });

      expect(model.maxImagesPerCall).toBe(4);
    });

    it('exposes correct maxImagesPerCall for pixelart-v1-turbo', () => {
      const model = new PixelArtImageModel('pixelart-v1-turbo', {
        provider: 'pixelart.image',
        baseURL: 'https://api.pixelart.ai/v1',
        headers: () => ({ Authorization: 'Bearer key' }),
      });

      expect(model.maxImagesPerCall).toBe(1);
    });

    it('defaults maxImagesPerCall to 1 for unknown models', () => {
      const model = new PixelArtImageModel('pixelart-unknown', {
        provider: 'pixelart.image',
        baseURL: 'https://api.pixelart.ai/v1',
        headers: () => ({ Authorization: 'Bearer key' }),
      });

      expect(model.maxImagesPerCall).toBe(1);
    });
  });
});

